У меня есть вот такой тестовый клиент RabbitMQ:
class RabbitMQTestClient:
    def __init__(self, rabbitmq_url: str) -> None:
        self._params = pika.URLParameters(rabbitmq_url)

    def _with_channel(self, action):
        connection = pika.BlockingConnection(self._params)
        try:
            channel = connection.channel()
            return action(channel)
        finally:
            connection.close()

    async def purge_queue(self, queue_name: str) -> None:
        def action(channel):
            channel.queue_declare(queue=queue_name, durable=True)
            channel.queue_purge(queue=queue_name)

        await asyncio.to_thread(self._with_channel, action)

    async def delete_queue(self, queue_name: str) -> None:
        def action(channel):
            channel.queue_delete(queue=queue_name, if_unused=False, if_empty=False)

        await asyncio.to_thread(self._with_channel, action)

    async def read_messages(self, queue_name: str) -> list[dict]:
        def action(channel):
            channel.queue_declare(queue=queue_name, durable=True)
            messages: list[dict] = []
            while True:
                method, _, body = channel.basic_get(queue=queue_name, auto_ack=True)
                if method is None or body is None:
                    break
                messages.append(json.loads(body.decode("utf-8")))
            return messages

        return await asyncio.to_thread(self._with_channel, action)

Я подумал что вместо этого можно использовать самый обычный rabbitmq клиент, но просто модернизировать функцию отправки сообщени добавляя каждое сообщение в словарь messages. Еще именно этот клиент создал мне огромное количество очередей и не удаляет их. Вот моя идея наследоваться от обычного клиента брокера и через super().publish вызывать существующий метод и добавить messages.append или что то подобное

